namespace sv_bdeab54d156b4095ac3f9948c5139e6c.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_bdeab54d156b4095ac3f9948c5139e6c.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel.Id);
}

.channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.active .channel-name {
    color: #ffffff;
}

.unread-badge {
    background-color: #e74c3c;
    color: white;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #4a90d9;
}

.send-button {
    padding: 8px 20px;
    background: #4a90d9;
    color: white;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background-color 0.15s;
    white-space: nowrap;
}

.send-button:hover:not(:disabled) {
    background: #357abd;
}

.send-button:disabled {
    background: #b0b0b0;
    cursor: not-allowed;
}

@using sv_bdeab54d156b4095ac3f9948c5139e6c.Services

<div class="message-bubble" @onmouseenter="() => _showActions = true" @onmouseleave="() => _showActions = false">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions && ShowActions)
    {
        <div class="action-bar">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">💬 Reply</button>
            <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">😀 React</button>
        </div>

        @if (_showEmojiPicker)
        {
            <div class="emoji-picker">
                @foreach (var emoji in _commonEmojis)
                {
                    <button class="emoji-btn" @onclick="() => PickEmoji(emoji)">@emoji</button>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public bool ShowActions { get; set; } = true;
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.message-bubble {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.45;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    font-size: 0.8rem;
    border: 1px solid #ddd;
    border-radius: 12px;
    background: #f0f0f0;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e0e0f0;
    border-color: #aab;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    font-size: 0.82rem;
    color: #4a90d9;
    background: none;
    border: none;
    cursor: pointer;
    padding: 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    padding: 2px;
    z-index: 10;
}

.action-btn {
    padding: 4px 10px;
    font-size: 0.78rem;
    border: none;
    background: none;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -8px;
    right: 180px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    padding: 4px;
    z-index: 11;
}

.emoji-btn {
    font-size: 1.2rem;
    padding: 4px 6px;
    border: none;
    background: none;
    cursor: pointer;
    border-radius: 4px;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

