arguments.file_text:
@using sv_bdeab54d156b4095ac3f9948c5139e6c.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2c2f33;
    color: #e0e0e0;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_bdeab54d156b4095ac3f9948c5139e6c.Services

<div class="message-area">
    <div class="area-header">
        <h3># @ChannelName</h3>
        <span class="area-description">@ChannelDescription</span>
    </div>
    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        else if (HasMoreMessages)
        {
            <button class="load-more-btn" @onclick="OnLoadMore">Load older messages</button>
        }

        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           ReplyCount="GetReplyCount(msg.Id)"
                           OnOpenThread="OnOpenThread"
                           OnReact="async emoji => await HandleReaction(msg.Id, emoji)" />
        }
    </div>
    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public Dictionary<int, int> ThreadReplyCounts { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }

    private int GetReplyCount(int messageId) =>
        ThreadReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleReaction(int messageId, string emoji) =>
        await OnReactionAdded.InvokeAsync((messageId, emoji));

    private async Task HandleScroll()
    {
        // Scroll-to-top detection is handled via the "Load older messages" button
        // for reliability without JS interop
        await Task.CompletedTask;
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1a1a;
}

.area-description {
    font-size: 0.82rem;
    color: #777;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.85rem;
    color: #999;
}

.load-more-btn {
    display: block;
    margin: 8px auto;
    padding: 6px 16px;
    font-size: 0.82rem;
    color: #4a90d9;
    background: none;
    border: 1px solid #4a90d9;
    border-radius: 6px;
    cursor: pointer;
}

.load-more-btn:hover {
    background: #f0f5ff;
}

@using sv_bdeab54d156b4095ac3f9948c5139e6c.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageBubble Message="RootMessage" ShowActions="false" />
        </div>

        <div class="thread-replies">
            @if (Replies.Count > 0)
            {
                <div class="reply-divider">
                    <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
                </div>
            }

            @foreach (var reply in Replies)
            {
                <MessageBubble Message="reply" ShowActions="false" />
            }
        </div>

        <MessageInput Placeholder="Reply in thread…" ButtonLabel="Reply" OnSubmit="OnSendReply" />
    }
</div>

@code {
