    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #e0e0e0;
    color: #333;
}

.thread-root {
    padding: 8px 0;
    border-bottom: 1px solid #e8e8e8;
    background: #f0f0f0;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
