    @if (_isThreadOpen)
    {
        <div class="thread-panel-container">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int? _selectedChannelId;
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = new();
    private bool _hasMoreMessages;
    private bool _isLoadingMore;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadReplyCounts = new();
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _hasMoreMessages = messages.Count >= PageSize;

        await BuildThreadReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_selectedChannelId is null || _isLoadingMore) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messages.Count, PageSize);
        _isLoadingMore = false;

        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            await BuildThreadReplyCounts();
        }

        _hasMoreMessages = older.Count >= PageSize;
    }

    private async Task BuildThreadReplyCounts()
    {
        // Identify messages that are thread starters (have replies referencing them)
        var rootIds = _messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var replyCounts = _messages
            .Where(m => m.ReplyToId is not null && rootIds.Contains(m.ReplyToId.Value))
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());

        // Also check for threads via the service for root messages
        foreach (var msg in _messages.Where(m => m.ReplyToId is null))
        {
            if (!replyCounts.ContainsKey(msg.Id))
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                if (thread.Count > 0)
                {
                    replyCounts[msg.Id] = thread.Count;
                }
            }
        }

        _threadReplyCounts = replyCounts;
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _isThreadOpen = true;
    }

    private async Task CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
        await Task.CompletedTask;
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task SendThreadReply(string content)
    {
        if (_selectedChannelId is null || _threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var msgIndex = _messages.FindIndex(m => m.Id == args.MessageId);
        if (msgIndex >= 0)
        {
            var msg = _messages[msgIndex];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == args.Emoji);
            if (existing >= 0)
            {
                var r = reactions[existing];
                reactions[existing] = r with { Users = [..r.Users, "You"] };
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
            _messages[msgIndex] = msg with { Reactions = reactions };
        }
    }
}

